import{_ as o}from"./Menu.179edc93.js";import{u as a}from"./composables.96d18f89.js";import{r as e,a as r,e as l,b as u,f as n,o as c}from"./entry.7b9f66e3.js";const m=""+new URL("article-design-emotionnel.2e2af670.png",import.meta.url).href,d=""+new URL("article-design-emotionnel-img-2.2e513824.png",import.meta.url).href,p=""+new URL("article-design-emotionnel-duolingo.c9879eab.png",import.meta.url).href,g=""+new URL("article-design-emotionnel-raclette.bbe5f7e7.jpg",import.meta.url).href,h=""+new URL("article-design-emotionnel-materiel.d941180c.png",import.meta.url).href,v={class:"banniere"},f=n('<div class="margium-l marge-haute-l"><div class="espacium"><div class="colonnes"><div class="colonne"><h1>Le Design \xE9motionnel</h1><div class="projettitre"></div> 20 juillet 2022 \xB7 2 min </div><div class="colonne"></div></div></div></div>',1),_=n('<article class="margium-l marge-haute-l marge-basse-l"><div class="espacium"><div class="coldroite"><p> Si nous \xE9tions rationnels, une bonne exp\xE9rience se r\xE9sumerait \xE0 design utile et utilisable. Toutefois, nous sommes des humains et donc fondamentalement irrationnels, nous \xE9prouvons des \xE9motions et des sentiments qui guident nos comportements.</p><h2>Le design \xE9motionnel c&#39;est quoi ?</h2><img src="'+m+'" loading="lazy" alt="sch\xE9ma du design \xE9motionnel : Pyramide avec en partant du bas fonctionnel, Fiable, Utilisable et en haut le design \xE9motionnel : Agr\xE9able"><p> Le design \xE9motionnel c\u2019est donner un aspect Humain, une personnalit\xE9, aux interfaces homme-machines. Avoir des interfaces utilisables n\u2019est pas suffisant dans une d\xE9marche de design \xE9motionnel, il faut la rendre agr\xE9able. De sorte que l&#39;exp\xE9rience d&#39;utilisation est plaisante. <br><br> Don Norman, chercheur en science cognitive d\xE9crit l\u2019effet esth\xE9tique-utilisabilit\xE9 ainsi : les choses attrayantes fonctionnent mieux. </p><h2>Pourquoi faire du design \xE9motionnel ?</h2><p>Les exp\xE9riences \xE9motionnelles nous laissent davantage de souvenir dans notre m\xE9moire \xE0 long terme. Les \xE9motions positives favoriseront le processus de m\xE9morisation, cela g\xE9n\xE8re de la dopamine, ce qui nous motive \xE0 aller au bout des actions (acte d&#39;achat, terminer une proc\xE9dure ...) et active notre circuit de r\xE9compense. Nous sommes plus enclins \xE0 r\xE9it\xE9rer l&#39;exp\xE9rience per\xE7ue comme positive. Nous sommes davantage attach\xE9s \xE0 un service ou \xE0 un produit.</p><p>On note selon Don Norman 3 niveaux d&#39;affects interconnect\xE9s qui agissent sur nos actions :</p><img src="'+d+'" loading="lazy" alt="sch\xE9ma des niveaux d&#39;affects du design \xE9motionnel"><h2>Comment faire du design \xE9motionnel ?</h2><ul><li><h3>Utiliser une mascotte mignonne</h3><img src="'+p+'" loading="lazy" alt="mascotte de l&#39;application d\u2019apprentissage de langue Duolingo"><p>De nombreuses entreprises prennent une mascotte \xAB mignonne \xBB pour susciter des \xE9motions aux utilisateurs de leur service comme Duolingo, Waze, Kakao talk. Nous sommes programm\xE9s pour d\xE9tecter des \xE9motions sur les visages. Le choix de photos et d\u2019illustrations pr\xE9sentant des sujets nous influence fortement et inconsciemment.</p></li><li><h3>Utiliser l&#39;humour</h3><img src="'+g+'" loading="lazy" alt="capture du site web raclette world"><p>Le site raclette.world est un calculateur de quantit\xE9 de raclette, en sois rien d&#39;extra-ordinaire, pourtant ce site \xE0 vu sont nombre de visite exploser. La raison ? Son ton volontairement d\xE9cal\xE9 et humoristique. D&#39;autre entreprises on recours </p></li><li><h3>Utiliser les codes de votre audience</h3><img src="'+h+'" loading="lazy" alt="capture du site mat\xE9riel point net"><p>Voici la page d&#39;un panier vide sur le site e-commerce Materiel.net, le site est orient\xE9 joueur de jeux vid\xE9o. Le message et l&#39;illustration reprennent les codes du jeu pour inciter les internautes \xE0 poursuivre leurs achats.</p></li><li><h3>Utiliser un design singulier</h3><p> Beaucoup de site web se ressemblent, pour susciter l&#39;\xE9motion, n&#39;utiliser d&#39;image de banque d&#39;images ou de th\xE8me cl\xE9 en main. Prenez vos propres photos, adoptez un design atypique comme \xC9cosia, Welcome to the jungle ou the Verge. </p></li></ul><p> Pour aller plus loin sur le sujet, vous pouvez consulter l\u2019ouvrage d&#39;Aarron Walter, \xABDesign \xE9motionnel\xBB. </p></div></div></article>',1),j={__name:"le-design-emotionnel",setup(b){const i=e("Le Design \xE9motionnel - Lucas Lacroix"),s=e("Si nous \xE9tions rationnels, une bonne exp\xE9rience se r\xE9sumerait \xE0 design utile et utilisable. Toutefois, nous sommes des humains et donc fondamentalement irrationnels, nous \xE9prouvons des");return a({title:i,meta:[{name:"description",content:s}]}),(x,L)=>{const t=o;return c(),r("div",null,[l("div",v,[u(t),f]),_])}}};export{j as default};
